#include <stdio.h>
#include <stdlib.h>

// Define the structure for a tree node
typedef struct TreeNode {
    int val;
    struct TreeNode *left;
    struct TreeNode *right;
} TreeNode;

// Function to create a new tree node
TreeNode* createTreeNode(int val) {
    TreeNode* newNode = (TreeNode*) malloc(sizeof(TreeNode));
    if (!newNode) {
        printf("Memory error\n");
        return NULL;
    }
    newNode->val = val;
    newNode->left = newNode->right = NULL;
    return newNode;
}

// Function to check if a binary tree satisfies the children sum property
int isChildrenSum(TreeNode* root) {
    if (root == NULL || (root->left == NULL && root->right == NULL))
        return 1;

    int leftVal = (root->left) ? root->left->val : 0;
    int rightVal = (root->right) ? root->right->val : 0;

    if (root->val != leftVal + rightVal)
        return 0;

    return isChildrenSum(root->left) && isChildrenSum(root->right);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        TreeNode** nodes = (TreeNode**) malloc(N * sizeof(TreeNode*));
        for (int i = 0; i < N; i++) {
            int val;
            scanf("%d", &val);
            nodes[i] = createTreeNode(val);
        }
        for (int i = 0; i < N; i++) {
            int left = 2 * i + 1;
            int right = 2 * i + 2;
            if (left < N)
                nodes[i]->left = nodes[left];
            if (right < N)
                nodes[i]->right = nodes[right];
        }
        printf("%s\n", isChildrenSum(nodes[0]) ? "true" : "false");
        free(nodes);
    }
    return 0;
}

