import java.util.Scanner;
public class Main {
    static class TreeNode {
        int val;
        TreeNode left;
        TreeNode right;
        TreeNode(int x) { val = x; }
    }

    public static boolean isChildrenSum(TreeNode root) {
        if (root == null || (root.left == null && root.right == null))
            return true;

        int leftVal = (root.left != null) ? root.left.val : 0;
        int rightVal = (root.right != null) ? root.right.val : 0;

        if (root.val != leftVal + rightVal)
            return false;

        return isChildrenSum(root.left) && isChildrenSum(root.right);
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            int N = scanner.nextInt();
            TreeNode[] nodes = new TreeNode[N];
            for (int i = 0; i < N; i++) {
                int val = scanner.nextInt();
                nodes[i] = new TreeNode(val);
            }
            for (int i = 0; i < N; i++) {
                int left = 2 * i + 1;
                int right = 2 * i + 2;
                if (left < N)
                    nodes[i].left = nodes[left];
                if (right < N)
                    nodes[i].right = nodes[right];
            }
            System.out.println(isChildrenSum(nodes[0]));
        }
    }
}

